import React, { useState, useEffect } from 'react';
import { useAuth } from '../../contexts/AuthContext';
import { quizAPI } from '../../services/api';
import QuizQuestion from './QuizQuestion';
import QuizResults from './QuizResults';
import './Quiz.css';

const Quiz = () => {
  const [questions, setQuestions] = useState([]);
  const [currentQuestion, setCurrentQuestion] = useState(0);
  const [answers, setAnswers] = useState([]);
  const [showResults, setShowResults] = useState(false);
  const [results, setResults] = useState(null);
  const [loading, setLoading] = useState(true);
  const [quizStarted, setQuizStarted] = useState(false);

  const { user } = useAuth();

  useEffect(() => {
    // Mock questions for now - in real app, fetch from backend
    const mockQuestions = [
      {
        id: 1,
        question: "What type of activities do you enjoy most?",
        options: [
          "Solving complex problems and puzzles",
          "Helping and teaching others",
          "Creating art or designing things",
          "Organizing and planning events",
          "Working with technology and computers"
        ],
        category: "interests"
      },
      {
        id: 2,
        question: "Which skills do you feel most confident about?",
        options: [
          "Programming and technical skills",
          "Communication and leadership",
          "Creative thinking and design",
          "Analytical and mathematical skills",
          "Research and investigation"
        ],
        category: "skills"
      },
      {
        id: 3,
        question: "What is your preferred work environment?",
        options: [
          "Office setting with clear structure",
          "Flexible remote work",
          "Creative studio or lab",
          "Outdoor or field work",
          "Team-based collaborative space"
        ],
        category: "preferences"
      },
      {
        id: 4,
        question: "Which subjects interest you the most?",
        options: [
          "Computer Science and Technology",
          "Business and Management",
          "Arts and Design",
          "Science and Research",
          "Healthcare and Medicine"
        ],
        category: "academic"
      },
      {
        id: 5,
        question: "How do you prefer to learn new things?",
        options: [
          "Hands-on practice and experimentation",
          "Reading books and documentation",
          "Watching video tutorials",
          "Working in study groups",
          "Taking structured courses"
        ],
        category: "learning"
      }
    ];
    
    setQuestions(mockQuestions);
    setLoading(false);
  }, []);

  const startQuiz = () => {
    setQuizStarted(true);
  };

  const handleAnswer = (answerIndex) => {
    const newAnswers = [...answers];
    newAnswers[currentQuestion] = answerIndex;
    setAnswers(newAnswers);

    if (currentQuestion < questions.length - 1) {
      setCurrentQuestion(currentQuestion + 1);
    } else {
      submitQuiz(newAnswers);
    }
  };

  const submitQuiz = async (quizAnswers) => {
    setLoading(true);
    try {
      // Mock results for now - in real app, submit to backend
      const mockResults = {
        score: Math.floor(Math.random() * 30) + 70, // Random score between 70-100
        careers: ["Software Developer", "Data Scientist", "AI Engineer", "UX Designer"],
        courses: [
          { 
            name: "Full Stack Web Development", 
            platform: "Coursera", 
            link: "https://coursera.org",
            duration: "6 months",
            level: "Beginner"
          },
          { 
            name: "Machine Learning Specialization", 
            platform: "Udemy", 
            link: "https://udemy.com",
            duration: "3 months",
            level: "Intermediate"
          },
          { 
            name: "Data Structures and Algorithms", 
            platform: "edX", 
            link: "https://edx.org",
            duration: "4 months",
            level: "Intermediate"
          }
        ],
        field: "Technology",
        strengths: ["Analytical Thinking", "Problem Solving", "Technical Aptitude"],
        recommendations: "Based on your answers, you show strong aptitude for technology-related careers. Consider focusing on software development or data science roles."
      };
      
      setResults(mockResults);
      setShowResults(true);
      
      // In real app, save to backend
      // const results = await quizAPI.submitQuiz(quizAnswers);
      // setResults(results);
      
    } catch (error) {
      console.error('Error submitting quiz:', error);
    } finally {
      setLoading(false);
    }
  };

  const goBack = () => {
    if (currentQuestion > 0) {
      setCurrentQuestion(currentQuestion - 1);
    }
  };

  const retakeQuiz = () => {
    setCurrentQuestion(0);
    setAnswers([]);
    setShowResults(false);
    setResults(null);
    setQuizStarted(false);
  };

  if (!user) {
    return (
      <div className="quiz-container">
        <div className="container">
          <div className="auth-required">
            <h2>Authentication Required</h2>
            <p>Please log in to take the career assessment quiz.</p>
          </div>
        </div>
      </div>
    );
  }

  if (loading && !quizStarted) {
    return (
      <div className="quiz-container">
        <div className="container">
          <div className="loading">Loading quiz...</div>
        </div>
      </div>
    );
  }

  if (showResults && results) {
    return <QuizResults results={results} onRetake={retakeQuiz} />;
  }

  if (!quizStarted) {
    return (
      <div className="quiz-container">
        <div className="container">
          <div className="quiz-intro">
            <h1>Career Assessment Quiz</h1>
            <p className="quiz-description">
              Discover your ideal career path with our intelligent assessment. 
              Answer 5 simple questions about your interests, skills, and preferences.
            </p>
            
            <div className="quiz-info">
              <div className="info-card">
                <h3>What to expect:</h3>
                <ul>
                  <li>⏱️ 5-7 minutes to complete</li>
                  <li>🎯 Personalized career matches</li>
                  <li>📚 Curated learning resources</li>
                  <li>💡 Actionable insights</li>
                </ul>
                
                <div className="quiz-stats">
                  <div className="stat">
                    <h4>5</h4>
                    <p>Questions</p>
                  </div>
                  <div className="stat">
                    <h4>100%</h4>
                    <p>Free</p>
                  </div>
                  <div className="stat">
                    <h4>Instant</h4>
                    <p>Results</p>
                  </div>
                </div>
                
                <button onClick={startQuiz} className="btn btn-primary start-quiz-btn">
                  Start Career Assessment
                </button>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="quiz-container">
      <div className="quiz-progress">
        <div 
          className="progress-bar" 
          style={{ width: `${((currentQuestion + 1) / questions.length) * 100}%` }}
        ></div>
        <span>Question {currentQuestion + 1} of {questions.length}</span>
      </div>

      {questions.length > 0 && (
        <QuizQuestion
          question={questions[currentQuestion]}
          questionNumber={currentQuestion + 1}
          totalQuestions={questions.length}
          onAnswer={handleAnswer}
          selectedAnswer={answers[currentQuestion]}
          onBack={goBack}
          canGoBack={currentQuestion > 0}
        />
      )}
    </div>
  );
};

export default Quiz;
